import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService, resolveTimeRange } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'confirmed',
    createdAt: new Date('2026-01-15T12:00:00Z'),
    updatedAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2026-01-15T12:00:00Z'),
    updatedAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

/** Fixed custom query for Jan 1–31, 2026. */
const JAN_QUERY: AnalyticsQuery = {
  timeRange: 'custom',
  startDate: '2026-01-01T00:00:00Z',
  endDate: '2026-01-31T23:59:59Z',
};

/** Previous period: Dec 1–31, 2025 (same duration, immediately before). */
const DEC_START = new Date('2025-12-01T00:00:01Z');
const DEC_END = new Date('2025-12-31T23:59:58Z');

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // =========================================================================
  // resolveTimeRange
  // =========================================================================

  describe('resolveTimeRange', () => {
    it('should resolve 24h range', () => {
      const { start, end } = resolveTimeRange({ timeRange: '24h' });
      const diffMs = end.getTime() - start.getTime();
      expect(Math.abs(diffMs - 24 * 60 * 60 * 1000)).toBeLessThan(100);
    });

    it('should resolve 7d range', () => {
      const { start, end } = resolveTimeRange({ timeRange: '7d' });
      const diffMs = end.getTime() - start.getTime();
      expect(Math.abs(diffMs - 7 * 24 * 60 * 60 * 1000)).toBeLessThan(100);
    });

    it('should resolve 30d range', () => {
      const { start, end } = resolveTimeRange({ timeRange: '30d' });
      const diffMs = end.getTime() - start.getTime();
      expect(Math.abs(diffMs - 30 * 24 * 60 * 60 * 1000)).toBeLessThan(100);
    });

    it('should resolve 90d range', () => {
      const { start, end } = resolveTimeRange({ timeRange: '90d' });
      const diffMs = end.getTime() - start.getTime();
      expect(Math.abs(diffMs - 90 * 24 * 60 * 60 * 1000)).toBeLessThan(100);
    });

    it('should resolve custom range with explicit dates', () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-31T23:59:59Z',
      };
      const { start, end } = resolveTimeRange(query);
      expect(start.toISOString()).toBe('2026-01-01T00:00:00.000Z');
      expect(end.toISOString()).toBe('2026-01-31T23:59:59.000Z');
    });

    it('should throw on custom range without dates', () => {
      expect(() => resolveTimeRange({ timeRange: 'custom' })).toThrow(
        'startDate and endDate are required',
      );
    });

    it('should throw on custom range with only startDate', () => {
      expect(() =>
        resolveTimeRange({ timeRange: 'custom', startDate: '2026-01-01T00:00:00Z' }),
      ).toThrow('startDate and endDate are required');
    });

    it('should throw on custom range with only endDate', () => {
      expect(() =>
        resolveTimeRange({ timeRange: 'custom', endDate: '2026-01-31T00:00:00Z' }),
      ).toThrow('startDate and endDate are required');
    });
  });

  // =========================================================================
  // getDashboard — empty data
  // =========================================================================

  describe('getDashboard', () => {
    it('should return a well-shaped dashboard with empty data', async () => {
      const result = await service.getDashboard({ timeRange: '30d' });

      expect(result.summaries).toHaveLength(4);
      expect(result.summaries.map((s) => s.metric)).toEqual([
        'orders',
        'revenue',
        'users',
        'products',
      ]);
      expect(result.revenueTimeSeries.metric).toBe('revenue');
      expect(result.orderTimeSeries.metric).toBe('order_count');
      expect(result.topProducts).toEqual([]);
      expect(result.generatedAt).toBeTruthy();
    });

    it('should return all zero values and flat trends when no data exists', async () => {
      const result = await service.getDashboard(JAN_QUERY);

      for (const s of result.summaries) {
        expect(s.currentValue).toBe(0);
        expect(s.previousValue).toBe(0);
        expect(s.changePercent).toBe(0);
        expect(s.trend).toBe('flat');
      }
    });

    it('should populate summaries from seeded orders and users', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 50,
          items: [{ productId: 'p1', name: 'A', quantity: 3, unitPrice: 10 }],
          createdAt: new Date('2026-01-10T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 30,
          items: [{ productId: 'p2', name: 'B', quantity: 2, unitPrice: 15 }],
          createdAt: new Date('2026-01-20T10:00:00Z'),
        }),
      );
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2026-01-05T10:00:00Z') }));

      const result = await service.getDashboard(JAN_QUERY);

      const ordersSummary = result.summaries.find((s) => s.metric === 'orders')!;
      expect(ordersSummary.currentValue).toBe(2);

      const revenueSummary = result.summaries.find((s) => s.metric === 'revenue')!;
      expect(revenueSummary.currentValue).toBe(80);

      const usersSummary = result.summaries.find((s) => s.metric === 'users')!;
      expect(usersSummary.currentValue).toBe(1);

      const productsSummary = result.summaries.find((s) => s.metric === 'products')!;
      expect(productsSummary.currentValue).toBe(5); // 3 + 2
    });
  });

  // =========================================================================
  // getMetricDetail — computeSummary + buildTimeSeries
  // =========================================================================

  describe('getMetricDetail', () => {
    it('should return detail for a valid metric type', async () => {
      const result = await service.getMetricDetail('revenue', { timeRange: '7d' });

      expect(result.summary.metric).toBe('revenue');
      expect(result.summary.label).toBe('Total Revenue');
      expect(result.timeSeries).toBeDefined();
      expect(result.generatedAt).toBeTruthy();
    });

    it('should compute correct revenue summary', async () => {
      orderRepo.save(
        makeOrder({ id: 'o1', total: 100, createdAt: new Date('2026-01-10T10:00:00Z') }),
      );
      orderRepo.save(
        makeOrder({ id: 'o2', total: 200, createdAt: new Date('2026-01-20T10:00:00Z') }),
      );

      const result = await service.getMetricDetail('revenue', JAN_QUERY);
      expect(result.summary.currentValue).toBe(300);
    });

    it('should compute correct order count summary', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-01-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-01-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2026-01-20T10:00:00Z') }));

      const result = await service.getMetricDetail('orders', JAN_QUERY);
      expect(result.summary.currentValue).toBe(3);
    });

    it('should compute correct user count summary', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2026-01-05T10:00:00Z') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2026-01-15T10:00:00Z') }));

      const result = await service.getMetricDetail('users', JAN_QUERY);
      expect(result.summary.currentValue).toBe(2);
    });

    it('should compute products sold (sum of quantities)', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'A', quantity: 5, unitPrice: 10 },
            { productId: 'p2', name: 'B', quantity: 3, unitPrice: 20 },
          ],
          total: 110,
          createdAt: new Date('2026-01-10T10:00:00Z'),
        }),
      );

      const result = await service.getMetricDetail('products', JAN_QUERY);
      expect(result.summary.currentValue).toBe(8); // 5 + 3
    });

    // -----------------------------------------------------------------------
    // Period-over-period comparison
    // -----------------------------------------------------------------------

    it('should compute upward trend when current > previous', async () => {
      // Previous period (Dec): 1 order
      orderRepo.save(makeOrder({ id: 'o-prev', createdAt: new Date('2025-12-15T10:00:00Z') }));
      // Current period (Jan): 3 orders
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-01-05T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-01-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2026-01-25T10:00:00Z') }));

      const result = await service.getMetricDetail('orders', JAN_QUERY);
      expect(result.summary.currentValue).toBe(3);
      expect(result.summary.previousValue).toBe(1);
      expect(result.summary.trend).toBe('up');
      expect(result.summary.changePercent).toBe(200); // (3-1)/1 * 100
    });

    it('should compute downward trend when current < previous', async () => {
      // Previous period: 3 orders
      orderRepo.save(makeOrder({ id: 'o-p1', createdAt: new Date('2025-12-05T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o-p2', createdAt: new Date('2025-12-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o-p3', createdAt: new Date('2025-12-25T10:00:00Z') }));
      // Current period: 1 order
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-01-15T10:00:00Z') }));

      const result = await service.getMetricDetail('orders', JAN_QUERY);
      expect(result.summary.currentValue).toBe(1);
      expect(result.summary.previousValue).toBe(3);
      expect(result.summary.trend).toBe('down');
      expect(result.summary.changePercent).toBeCloseTo(-66.67, 1);
    });

    it('should show flat trend when both periods are zero', async () => {
      const result = await service.getMetricDetail('orders', JAN_QUERY);
      expect(result.summary.currentValue).toBe(0);
      expect(result.summary.previousValue).toBe(0);
      expect(result.summary.changePercent).toBe(0);
      expect(result.summary.trend).toBe('flat');
    });

    it('should show 100% change when previous is zero but current is positive', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-01-15T10:00:00Z') }));

      const result = await service.getMetricDetail('orders', JAN_QUERY);
      expect(result.summary.currentValue).toBe(1);
      expect(result.summary.previousValue).toBe(0);
      expect(result.summary.changePercent).toBe(100);
      expect(result.summary.trend).toBe('up');
    });

    // -----------------------------------------------------------------------
    // Time series
    // -----------------------------------------------------------------------

    it('should generate time series points matching granularity', async () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-03T00:00:00Z',
        granularity: 'day',
      };

      orderRepo.save(
        makeOrder({ id: 'o1', total: 50, createdAt: new Date('2026-01-01T10:00:00Z') }),
      );
      orderRepo.save(
        makeOrder({ id: 'o2', total: 30, createdAt: new Date('2026-01-02T10:00:00Z') }),
      );

      const result = await service.getMetricDetail('revenue', query);
      expect(result.timeSeries.points.length).toBe(2); // 2 day buckets
      expect(result.timeSeries.points[0]!.value).toBe(50);
      expect(result.timeSeries.points[1]!.value).toBe(30);
    });

    it('should generate hourly buckets for short ranges', async () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-01T03:00:00Z',
        granularity: 'hour',
      };

      orderRepo.save(
        makeOrder({ id: 'o1', total: 10, createdAt: new Date('2026-01-01T00:30:00Z') }),
      );
      orderRepo.save(
        makeOrder({ id: 'o2', total: 20, createdAt: new Date('2026-01-01T01:30:00Z') }),
      );

      const result = await service.getMetricDetail('revenue', query);
      expect(result.timeSeries.points.length).toBe(3); // 3 hourly buckets
      expect(result.timeSeries.points[0]!.value).toBe(10);
      expect(result.timeSeries.points[1]!.value).toBe(20);
      expect(result.timeSeries.points[2]!.value).toBe(0);
    });

    it('should auto-select day granularity for a 7-day range', async () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-08T00:00:00Z',
      };

      const result = await service.getMetricDetail('orders', query);
      // 7 days → day granularity → 7 buckets
      expect(result.timeSeries.points.length).toBe(7);
    });

    it('should auto-select hour granularity for a 1-day range', async () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-02T00:00:00Z',
      };

      const result = await service.getMetricDetail('orders', query);
      // 1 day → hour granularity → 24 buckets
      expect(result.timeSeries.points.length).toBe(24);
    });

    it('should produce zero-valued points when no data exists in range', async () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-04T00:00:00Z',
        granularity: 'day',
      };

      const result = await service.getMetricDetail('revenue', query);
      for (const point of result.timeSeries.points) {
        expect(point.value).toBe(0);
      }
    });
  });

  // =========================================================================
  // getTopProducts
  // =========================================================================

  describe('getTopProducts', () => {
    it('should return an empty array when no orders exist', async () => {
      const result = await service.getTopProducts(JAN_QUERY, 5);
      expect(result).toEqual([]);
    });

    it('should return products sorted by revenue descending', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'Cheap', quantity: 10, unitPrice: 1 },
            { productId: 'p2', name: 'Expensive', quantity: 1, unitPrice: 100 },
          ],
          total: 110,
          createdAt: new Date('2026-01-10T10:00:00Z'),
        }),
      );

      const result = await service.getTopProducts(JAN_QUERY, 10);
      expect(result).toHaveLength(2);
      expect(result[0]!.productId).toBe('p2'); // Expensive first (100 > 10)
      expect(result[0]!.totalRevenue).toBe(100);
      expect(result[1]!.productId).toBe('p1');
      expect(result[1]!.totalRevenue).toBe(10);
    });

    it('should aggregate quantities and revenue across multiple orders', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          createdAt: new Date('2026-01-10T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          items: [{ productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 10 }],
          total: 30,
          createdAt: new Date('2026-01-20T10:00:00Z'),
        }),
      );

      const result = await service.getTopProducts(JAN_QUERY, 10);
      expect(result).toHaveLength(1);
      expect(result[0]!.totalQuantity).toBe(5);
      expect(result[0]!.totalRevenue).toBe(50);
      expect(result[0]!.orderCount).toBe(2);
    });

    it('should respect the limit parameter', async () => {
      for (let i = 0; i < 10; i++) {
        orderRepo.save(
          makeOrder({
            id: `o${i}`,
            items: [{ productId: `p${i}`, name: `Product ${i}`, quantity: 1, unitPrice: i + 1 }],
            total: i + 1,
            createdAt: new Date('2026-01-15T10:00:00Z'),
          }),
        );
      }

      const result = await service.getTopProducts(JAN_QUERY, 3);
      expect(result).toHaveLength(3);
      // Should be the top 3 by revenue
      expect(result[0]!.totalRevenue).toBe(10);
      expect(result[1]!.totalRevenue).toBe(9);
      expect(result[2]!.totalRevenue).toBe(8);
    });

    it('should count distinct orders per product correctly', async () => {
      // Same product in two different orders
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          createdAt: new Date('2026-01-10T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 30,
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );

      const result = await service.getTopProducts(JAN_QUERY, 10);
      expect(result).toHaveLength(1);
      expect(result[0]!.orderCount).toBe(2); // 2 distinct orders
      expect(result[0]!.totalQuantity).toBe(4); // 1 + 1 + 2
      expect(result[0]!.totalRevenue).toBe(40); // 10 + 10 + 20
    });

    it('should round revenue to 2 decimal places', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 9.99 }],
          total: 29.97,
          createdAt: new Date('2026-01-10T10:00:00Z'),
        }),
      );

      const result = await service.getTopProducts(JAN_QUERY, 10);
      expect(result[0]!.totalRevenue).toBe(29.97);
    });

    it('should only include orders within the date range', async () => {
      // In range
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
          total: 100,
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );
      // Out of range
      orderRepo.save(
        makeOrder({
          id: 'o2',
          items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 200 }],
          total: 200,
          createdAt: new Date('2026-03-01T10:00:00Z'),
        }),
      );

      const result = await service.getTopProducts(JAN_QUERY, 10);
      expect(result).toHaveLength(1);
      expect(result[0]!.productId).toBe('p1');
    });

    it('should handle single order with many items', async () => {
      const items = Array.from({ length: 20 }, (_, i) => ({
        productId: `p${i}`,
        name: `Product ${i}`,
        quantity: i + 1,
        unitPrice: 10,
      }));
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items,
          total: items.reduce((s, item) => s + item.quantity * item.unitPrice, 0),
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );

      const result = await service.getTopProducts(JAN_QUERY, 5);
      expect(result).toHaveLength(5);
      // Highest revenue product: p19, qty=20, revenue=200
      expect(result[0]!.productId).toBe('p19');
      expect(result[0]!.totalRevenue).toBe(200);
    });
  });

  // =========================================================================
  // Edge cases
  // =========================================================================

  describe('edge cases', () => {
    it('should handle a single data point', async () => {
      orderRepo.save(
        makeOrder({ id: 'o1', total: 42, createdAt: new Date('2026-01-15T10:00:00Z') }),
      );

      const result = await service.getMetricDetail('revenue', JAN_QUERY);
      expect(result.summary.currentValue).toBe(42);
    });

    it('should handle large datasets', async () => {
      // Insert 100 orders
      for (let i = 0; i < 100; i++) {
        orderRepo.save(
          makeOrder({
            id: `o${i}`,
            total: 10,
            createdAt: new Date(`2026-01-${String((i % 28) + 1).padStart(2, '0')}T12:00:00Z`),
          }),
        );
      }

      const result = await service.getMetricDetail('orders', JAN_QUERY);
      expect(result.summary.currentValue).toBe(100);

      const revenue = await service.getMetricDetail('revenue', JAN_QUERY);
      expect(revenue.summary.currentValue).toBe(1000);
    });

    it('should handle orders with zero total', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [{ productId: 'p1', name: 'Free', quantity: 1, unitPrice: 0 }],
          total: 0,
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );

      const revResult = await service.getMetricDetail('revenue', JAN_QUERY);
      expect(revResult.summary.currentValue).toBe(0);

      const orderResult = await service.getMetricDetail('orders', JAN_QUERY);
      expect(orderResult.summary.currentValue).toBe(1);
    });

    it('should handle orders with empty items array for products metric', async () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [],
          total: 0,
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );

      const result = await service.getMetricDetail('products', JAN_QUERY);
      expect(result.summary.currentValue).toBe(0);
    });

    it('should handle getDashboard with custom granularity', async () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-08T00:00:00Z',
        granularity: 'day',
      };

      const result = await service.getDashboard(query);
      expect(result.revenueTimeSeries.points.length).toBe(7);
      expect(result.orderTimeSeries.points.length).toBe(7);
    });

    it('should correctly label all metric types', async () => {
      const result = await service.getDashboard(JAN_QUERY);
      const labels = result.summaries.map((s) => s.label);
      expect(labels).toEqual(['Total Orders', 'Total Revenue', 'Active Users', 'Products Sold']);
    });
  });
});

